def generate_showback(cost_data, teams):
    report = {}
    for team in teams:
        team_costs = [c for c in cost_data if c['team'] == team]
        report[team] = {
            'total': sum(c['cost'] for c in team_costs),
            'by_service': {},
            'by_environment': {}
        }
        for cost in team_costs:
            report[team]['by_service'][cost['service']] = \
                report[team]['by_service'].get(cost['service'], 0) + cost['cost']
            report[team]['by_environment'][cost['environment']] = \
                report[team]['by_environment'].get(cost['environment'], 0) + cost['cost']
    return dict(sorted(report.items(), key=lambda x: x[1]['total'], reverse=True))

def calculate_chargeback(team_costs, shared_costs):
    total = sum(t['total'] for t in team_costs.values())
    return {team: {
        'direct': costs['total'],
        'shared': shared_costs * (costs['total'] / total),
        'total': costs['total'] + shared_costs * (costs['total'] / total)
    } for team, costs in team_costs.items()}
